func HasDonorWith(preds ...predicate.Contact) predicate.Finance {
	return predicate.Finance(func(s *sql.Selector) {
		step := newDonorStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Finance) predicate.Finance {
	return predicate.Finance(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Finance) predicate.Finance {
	return predicate.Finance(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Finance) predicate.Finance {
	return predicate.Finance(sql.NotPredicates(p))
}
